parameters.jsCode:
const data = items.map(item => item.json);

// Contadores
let resumen = {};
let total = data.length;

// Contar interacciones (logs)
let totalInteracciones = $items("log de navegacion").length;

// Recorrer datos
data.forEach(s => {
  const tipo = s.tipo || "Otros";
  const estado = (s.estado || "abierto").toLowerCase();

  if (!resumen[tipo]) {
    resumen[tipo] = {
      total: 0,
      abiertas: 0,
      en_proceso: 0,
      cerradas: 0
    };
  }

  resumen[tipo].total++;

  if (estado.includes("abierto")) resumen[tipo].abiertas++;
  else if (estado.includes("proceso")) resumen[tipo].en_proceso++;
  else if (estado.includes("cerrado")) resumen[tipo].cerradas++;
});

// Tipo más frecuente
let tipoMasFrecuente = "";
let max = 0;

for (let tipo in resumen) {
  if (resumen[tipo].total > max) {
    max = resumen[tipo].total;
    tipoMasFrecuente = tipo;
  }
}

// Crear texto
let texto = `Reporte de solicitudes\n\n`;
texto += `Resumen general\n`;
texto += `- Tipo más frecuente: ${tipoMasFrecuente}\n`;
texto += `- Total solicitudes: ${total}\n`;
texto += `- Interacciones con el bot: ${totalInteracciones}\n\n`;

texto += `Detalle por tipo\n`;

let i = 1;
for (let tipo in resumen) {
  const r = resumen[tipo];
  texto += `${i}) ${tipo}\n`;
  texto += `   - Total: ${r.total}\n`;
  texto += `   - Abiertas: ${r.abiertas}\n`;
  texto += `   - En proceso: ${r.en_proceso}\n`;
  texto += `   - Cerradas: ${r.cerradas}\n\n`;
  i++;
}

return [{ json: { texto } }];
